import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for p in fw.get('topLevelPackages', []):
                pkgs[(name, p['id'])] = p['resolvedVersion']
    return pkgs

bp = extract(b)
ap = extract(a)
diffs = [(k, bp[k], ap[k]) for k in bp if bp[k] != ap.get(k)]
if diffs:
    for d in diffs: print(f'CHANGED: {d}')
else:
    print('All package versions match between baseline and after-cpm.')
"

